13892   for (auto I = PredicatedSCEVRewrites.begin();
13893        I != PredicatedSCEVRewrites.end();) {
13894     std::pair<const SCEV *, const Loop *> Entry = I->first;
13895     if (ToForget.count(Entry.first))
