6157     X = FalseExpr;
6158     C = TrueExpr;
6159   } else {
6160     X = TrueExpr;
6161     C = FalseExpr;
6162   }
6163   return SE->getAddExpr(C, SE->getUMinExpr(CondExpr, SE->getMinusSCEV(X, C),
